exercise.solution:
@keyframes ping {
  from {
    transform: scale(1);
    opacity: 1;
  }
  to {
    transform: scale(1.6);
    opacity: 0;
  }
}

.notification-dot {
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background-color: #ef4444;
  animation: ping 1s ease-out infinite;
}

@media (prefers-reduced-motion: reduce) {
  .notification-dot {
    animation: none;
  }
}
